111	func (s *Service) GetRequest(ctx context.Context, requestID string) (*models.Contract, *models.Handset, error) {
112		if requestID == "" {
113			return nil, nil, fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
114		}
115	
116		contract, err := s.store.GetContractByRequestID(ctx, requestID)
117		if err != nil {
118			if errors.Is(err, terrors.ErrNotFound) {
119				return nil, nil, fmt.Errorf("contract not found for request_id: %w", terrors.ErrNotFound)
120			}
121			return nil, nil, fmt.Errorf("failed to get contract by request_id: %w", err)
122		}
123	
124		// If the contract already has all handset details captured at creation time, use them directly
125		// without a storage lookup. This preserves the pricing agreed at time of request.
126		if contract.HandsetName != "" && contract.ContractPricePence != "" && contract.RetailPricePence != "" && contract.ContractMonths != "" {
127			return contract, nil, nil
128		}
129	
130		h, err := s.store.GetHandsetByID(ctx, contract.HandsetID)
131		if err != nil {
132			return nil, nil, fmt.Errorf("failed to get handset for contract: %w", err)
133		}
134	
135		if h.CurrentProperties.RRPPence == 0 || h.CurrentProperties.RentalPricePence == 0 || h.CurrentProperties.ContractTermMonths == 0 {
136			return nil, nil, fmt.Errorf("handset has incomplete pricing data: %w", terrors.ErrFailedValidation)
137		}
138	
139		// If contract has a specific version, find that version's properties
140		if contract.HandsetVersion != "" && contract.HandsetVersion != h.CurrentProperties.Version {
141			for _, v := range h.Versions {
142				if v.Version == contract.HandsetVersion {
143					h.CurrentProperties = v
144					break
145				}
146			}
147		}
148	
149		return contract, h, nil
150	}
