392	// EligibilityStatusUpdate handles status update notifications from the eligibility provider.
393	// For DECLINED and WITHDRAWN statuses, the contract is moved to DECLINED.
394	func (s *Service) EligibilityStatusUpdate(ctx context.Context, requestID, statusStr string) error {
395		// @todo matt - this is a bit of a catch-all for any future status updates from the eligibility provider that require action. we don't really know what the statuses in the proto actually represent at this stage, neither do we know which are terminal states and how they should interact with the success/failure callbacks. consider this method WIP for the time being.
396		if requestID == "" {
397			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
398		}
399	
400		if statusStr != "DECLINED" && statusStr != "WITHDRAWN" {
401			tlog.WithAttribute("request_id", requestID).
402				WithAttribute("status", statusStr).
403				Info(ctx, "eligibility status update received, no action required")
404			return nil
405		}
406	
407		contract, err := s.store.GetContractByRequestID(ctx, requestID)
408		if err != nil {
409			return fmt.Errorf("failed to get contract: %w", err)
410		}
411	
412		if contract.Status != models.ContractStatusPendingEligibility {
413			tlog.WithAttribute("request_id", requestID).
414				WithAttribute("current_status", string(contract.Status)).
415				Info(ctx, "eligibility status update ignored, contract is not pending eligibility")
416			return nil
417		}
418	
419		if err := s.store.UpdateContractStatus(ctx, requestID, models.ContractStatusDeclined); err != nil {
420			return fmt.Errorf("failed to update contract status: %w", err)
421		}
422	
423		s.releaseHandsetStock(ctx, contract.HandsetID)
424	
425		if err := s.eventProducer.ProduceMobileHandsetContractDeclinedSync(ctx, &serviceevents.MobileHandsetContractDeclined{
426			ServiceId:  contract.ServiceID,
427			CustomerId: contract.CustomerID,
428			ContractId: contract.ID,
429			HandsetId:  contract.HandsetID,
430		}); err != nil {
431			tlog.WithError(err).
432				WithAttribute("contract_id", contract.ID).
433				Error(ctx, "failed to produce MobileHandsetContractDeclined event")
434		}
435	
436		tlog.WithAttribute("request_id", requestID).
437			WithAttribute("contract_id", contract.ID).
438			WithAttribute("status", statusStr).
439			Info(ctx, "eligibility status update, contract declined")
440	
441		return nil
442	}
