444	// checkPreEligibility perform pre-eligibility checks
445	func (s *Service) checkPreEligibility(ctx context.Context, customerID string) error {
446		// Check for declined contract
447		hasDeclined, err := s.store.CustomerHasDeclinedContract(ctx, customerID, s.backoffPeriod)
448		if err != nil {
449			return fmt.Errorf("failed to check declined contract: %w", err)
450		}
451		if hasDeclined {
452			return fmt.Errorf("a declined contract exists within the backup period: %w", terrors.ErrFailedValidation)
453		}
