459	// money converts a pence integer string (e.g. "4200") to a Money message with
460	// the amount expressed in pounds (e.g. "42.00"). The Money type is consumed by
461	// downstream services that treat Amount as a decimal pound value.
462	func money(penceStr string) *serviceevents.Money {
463		pence, err := strconv.Atoi(penceStr)
464		if err != nil {
465			return &serviceevents.Money{Amount: penceStr, Currency: currencyGBP}
466		}
467		return &serviceevents.Money{
468			Amount:   fmt.Sprintf("%.2f", float64(pence)/100),
469			Currency: currencyGBP,
470		}
471	}
